    public Object handleTrade(Client client, Object message)
    {
        //
        //    {
        //        "type": "message",
        //        "topic": "/contractMarket/execution:ADAUSDTM",
        //        "subject": "match",
        //        "data": {
        //            "makerUserId": "62286a4d720edf0001e81961",
        //            "symbol": "ADAUSDTM",
        //            "sequence": 41320766,
        //            "side": "sell",
        //            "size": 2,
        //            "price": 0.35904,
        //            "takerOrderId": "636dd9da9857ba00010cfa44",
        //            "makerOrderId": "636dd9c8df149d0001e62bc8",
        //            "takerUserId": "6180be22b6ab210001fa3371",
        //            "tradeId": "636dd9da0000d400d477eca7",
        //            "ts": 1668143578987357700
        //        }
        //    }
        //
        Object data = this.safeValue(message, "data", new java.util.HashMap<String, Object>() {{}});
        Object trade = this.parseTrade(data);
        Object symbol = Helpers.GetValue(trade, "symbol");
        Object trades = this.safeValue(this.trades, symbol);
        if (Helpers.isTrue(Helpers.isEqual(trades, null)))
        {
            Object limit = this.safeInteger(this.options, "tradesLimit", 1000);
            trades = new ArrayCache(((Number)limit).intValue());
            Helpers.addElementToObject(this.trades, symbol, trades);
        }
        Helpers.callDynamically(trades, "append", new Object[]{trade});
        Object messageHash = Helpers.add("trades:", symbol);
        client.resolve(trades, messageHash);
        return message;
    }

    /**
     * @method
     * @name kucoinfutures#watchOHLCV
     * @see https://www.kucoin.com/docs/websocket/futures-trading/public-channels/klines
     * @description watches historical candlestick data containing the open, high, low, and close price, and the volume of a market
     * @param {string} symbol unified symbol of the market to fetch OHLCV data for
     * @param {string} timeframe the length of time each candle represents
     * @param {int} [since] timestamp in ms of the earliest candle to fetch
     * @param {int} [limit] the maximum amount of candles to fetch
     * @param {object} [params] extra parameters specific to the exchange API endpoint
     * @returns {int[][]} A list of candles ordered as timestamp, open, high, low, close, volume
     */
    public java.util.concurrent.CompletableFuture<Object> watchOHLCV(Object symbol2, Object... optionalArgs)
    {
        final Object symbol3 = symbol2;
        return java.util.concurrent.CompletableFuture.supplyAsync(() -> {
            Object symbol = symbol3;
            Object timeframe = Helpers.getArg(optionalArgs, 0, "1m");
            Object since = Helpers.getArg(optionalArgs, 1, null);
            Object limit = Helpers.getArg(optionalArgs, 2, null);
            Object parameters = Helpers.getArg(optionalArgs, 3, new java.util.HashMap<String, Object>() {{}});
            (this.loadMarkets()).join();
            symbol = this.symbol(symbol);
            Object url = (this.negotiate(false)).join();
            Object marketId = this.marketId(symbol);
            Object timeframes = this.safeDict(this.options, "timeframes");
            Object timeframeId = this.safeString(timeframes, timeframe, timeframe);
            Object topic = Helpers.add(Helpers.add(Helpers.add("/contractMarket/limitCandle:", marketId), "_"), timeframeId);
            Object messageHash = Helpers.add(Helpers.add(Helpers.add("ohlcv::", symbol), "_"), timeframe);
            Object ohlcv = (this.subscribe(url, messageHash, topic, null, parameters)).join();
            if (Helpers.isTrue(this.newUpdates))
            {
                limit = Helpers.callDynamically(ohlcv, "getLimit", new Object[]{symbol, limit});
            }
            return this.filterBySinceLimit(ohlcv, since, limit, 0, true);
        }, io.github.ccxt.Exchange.VIRTUAL_EXECUTOR);

    }

    public void handleOHLCV(Client client, Object message)
    {
        //
        //    {
        //        "topic":"/contractMarket/limitCandle:LTCUSDTM_1min",
        //        "type":"message",
        //        "data":{
        //            "symbol":"LTCUSDTM",
        //            "candles":[
        //                "1715470980",
        //                "81.38",
        //                "81.38",
        //                "81.38",
        //                "81.38",
        //                "61.0",
        //                "61"
        //            ],
        //            "time":1715470994801
        //        },
        //        "subject":"candle.stick"
        //    }
        //
        Object topic = this.safeString(message, "topic");
        Object parts = Helpers.split(topic, "_");
        Object timeframeId = this.safeString(parts, 1);
        Object data = this.safeDict(message, "data");
        Object timeframes = this.safeDict(this.options, "timeframes");
        Object timeframe = this.findTimeframe(timeframeId, timeframes);
        Object marketId = this.safeString(data, "symbol");
        Object symbol = this.safeSymbol(marketId);
        Object messageHash = Helpers.add(Helpers.add(Helpers.add("ohlcv::", symbol), "_"), timeframe);
        Object ohlcv = this.safeList(data, "candles");
        Object parsed = new java.util.ArrayList<Object>(java.util.Arrays.asList(this.safeInteger(ohlcv, 0), this.safeNumber(ohlcv, 1), this.safeNumber(ohlcv, 2), this.safeNumber(ohlcv, 3), this.safeNumber(ohlcv, 4), this.safeNumber(ohlcv, 6)));
        
        Helpers.addElementToObject(this.ohlcvs, symbol, this.safeDict(this.ohlcvs, symbol, new java.util.HashMap<String, Object>() {{}}));
        if (!Helpers.isTrue((Helpers.inOp(Helpers.GetValue(this.ohlcvs, symbol), timeframe))))
        {
            Object limit = this.safeInteger(this.options, "OHLCVLimit", 1000);
            Helpers.addElementToObject(Helpers.GetValue(this.ohlcvs, symbol), timeframe, new ArrayCache.ArrayCacheByTimestamp(((Number)limit).intValue()));
        }
        Object stored = Helpers.GetValue(Helpers.GetValue(this.ohlcvs, symbol), timeframe);
        Helpers.callDynamically(stored, "append", new Object[]{parsed});
        client.resolve(stored, messageHash);
    }

    /**
     * @method
     * @name kucoinfutures#watchOrderBook
     * @description watches information on open orders with bid (buy) and ask (sell) prices, volumes and other data
     *   1. After receiving the websocket Level 2 data flow, cache the data.
     *   2. Initiate a REST request to get the snapshot data of Level 2 order book.
     *   3. Playback the cached Level 2 data flow.
     *   4. Apply the new Level 2 data flow to the local snapshot to ensure that the sequence of the new Level 2 update lines up with the sequence of the previous Level 2 data. Discard all the message prior to that sequence, and then playback the change to snapshot.
     *   5. Update the level2 full data based on sequence according to the size. If the price is 0, ignore the messages and update the sequence. If the size=0, update the sequence and remove the price of which the size is 0 out of level 2. For other cases, please update the price.
     *   6. If the sequence of the newly pushed message does not line up to the sequence of the last message, you could pull through REST Level 2 message request to get the updated messages. Please note that the difference between the start and end parameters cannot exceed 500.
     * @see https://docs.kucoin.com/futures/#level-2-market-data
     * @param {string} symbol unified symbol of the market to fetch the order book for
     * @param {int} [limit] the maximum amount of order book entries to return
     * @param {object} [params] extra parameters specific to the exchange API endpoint
     * @returns {object} A dictionary of [order book structures]{@link https://docs.ccxt.com/?id=order-book-structure} indexed by market symbols
     */
    public java.util.concurrent.CompletableFuture<Object> watchOrderBook(Object symbol, Object... optionalArgs)
    {

        return java.util.concurrent.CompletableFuture.supplyAsync(() -> {

            Object limit = Helpers.getArg(optionalArgs, 0, null);
            Object parameters = Helpers.getArg(optionalArgs, 1, new java.util.HashMap<String, Object>() {{}});
            return (this.watchOrderBookForSymbols(new java.util.ArrayList<Object>(java.util.Arrays.asList(symbol)), limit, parameters)).join();
        }, io.github.ccxt.Exchange.VIRTUAL_EXECUTOR);

    }

