            {
                throw new ArgumentsRequired((String)Helpers.add(this.id, " watchOrderBookForSymbols() requires a non-empty array of symbols")) ;
            }
            if (Helpers.isTrue(!Helpers.isEqual(limit, null)))
            {
                if (Helpers.isTrue(Helpers.isTrue((!Helpers.isEqual(limit, 20))) && Helpers.isTrue((!Helpers.isEqual(limit, 100)))))
                {
                    throw new ExchangeError((String)Helpers.add(this.id, " watchOrderBook 'limit' argument must be undefined, 20 or 100")) ;
                }
            }
            (this.loadMarkets()).join();
            symbols = this.marketSymbols(symbols);
