    public void handleDelta(Object orderbook, Object delta)
    {
        Helpers.addElementToObject(orderbook, "nonce", this.safeInteger(delta, "sequence"));
        Object timestamp = this.safeInteger(delta, "timestamp");
        Helpers.addElementToObject(orderbook, "timestamp", timestamp);
        Helpers.addElementToObject(orderbook, "datetime", this.iso8601(timestamp));
        Object change = this.safeValue(delta, "change", new java.util.HashMap<String, Object>() {{}});
        Object splitChange = Helpers.split(change, ",");
        Object price = this.safeNumber(splitChange, 0);
        Object side = this.safeString(splitChange, 1);
        Object quantity = this.safeNumber(splitChange, 2);
        Object type = ((Helpers.isTrue((Helpers.isEqual(side, "buy"))))) ? "bids" : "asks";
        Object value = new java.util.ArrayList<Object>(java.util.Arrays.asList(price, quantity));
        if (Helpers.isTrue(Helpers.isEqual(type, "bids")))
        {
            Object storedBids = Helpers.GetValue(orderbook, "bids");
            Helpers.callDynamically(storedBids, "storeArray", new Object[]{value});
        } else
        {
            Object storedAsks = Helpers.GetValue(orderbook, "asks");
            Helpers.callDynamically(storedAsks, "storeArray", new Object[]{value});
        }
    }

    public void handleDeltas(Object bookside, Object deltas)
    {
        for (var i = 0; Helpers.isLessThan(i, Helpers.getArrayLength(deltas)); i++)
        {
            this.handleDelta(bookside, Helpers.GetValue(deltas, i));
        }
    }

    public void handleOrderBook(Client client, Object message)
    {
        //
        // initial snapshot is fetched with ccxt's fetchOrderBook
        // the feed does not include a snapshot, just the deltas
        //
        //    {
        //        "type": "message",
        //        "topic": "/contractMarket/level2:ADAUSDTM",
        //        "subject": "level2",
        //        "data": {
        //            "sequence": 1668059586457,
        //            "change": "0.34172,sell,456", // type, side, quantity
        //            "timestamp": 1668573023223
        //        }
        //    }
        //
        Object data = this.safeValue(message, "data");
        Object topic = this.safeString(message, "topic");
        Object topicParts = Helpers.split(topic, ":");
        Object marketId = this.safeString(topicParts, 1);
        Object symbol = this.safeSymbol(marketId, null, "-");
        Object messageHash = Helpers.add("orderbook:", symbol);
        if (!Helpers.isTrue((Helpers.inOp(this.orderbooks, symbol))))
        {
            Object subscriptionArgs = this.safeDict(client.subscriptions, topic, new java.util.HashMap<String, Object>() {{}});
            Object limit = this.safeInteger(subscriptionArgs, "limit");
            
            Helpers.addElementToObject(this.orderbooks, symbol, this.orderBook(new java.util.HashMap<String, Object>() {{}}, limit));
        }
        Object storedOrderBook = Helpers.GetValue(this.orderbooks, symbol);
        Object nonce = this.safeInteger(storedOrderBook, "nonce");
        Object deltaEnd = this.safeInteger(data, "sequence");
        if (Helpers.isTrue(Helpers.isEqual(nonce, null)))
        {
            Object cacheLength = Helpers.getArrayLength(((java.util.List<Object>)Helpers.GetValue(storedOrderBook, "cache")));
            Object topicPartsNew = Helpers.split(topic, ":");
            Object topicSymbol = this.safeString(topicPartsNew, 1);
            Object topicChannel = this.safeString(topicPartsNew, 0);
            Object subscriptions = new java.util.ArrayList<Object>(((java.util.Map)client.subscriptions).keySet());
            Object subscription = null;
            for (var i = 0; Helpers.isLessThan(i, Helpers.getArrayLength(subscriptions)); i++)
            {
                Object key = Helpers.GetValue(subscriptions, i);
                if (Helpers.isTrue(Helpers.isTrue((Helpers.isGreaterThanOrEqual(Helpers.getIndexOf(key, topicSymbol), 0))) && Helpers.isTrue((Helpers.isGreaterThanOrEqual(Helpers.getIndexOf(key, topicChannel), 0)))))
                {
                    subscription = Helpers.GetValue(client.subscriptions, key);
                    break;
                }
            }
            Object limit = this.safeInteger(subscription, "limit");
            Object snapshotDelay = this.handleOption("watchOrderBook", "snapshotDelay", 5);
            if (Helpers.isTrue(Helpers.isEqual(cacheLength, snapshotDelay)))
            {
                this.spawn(() -> { try { this.loadOrderBook(client, messageHash, symbol, limit, new java.util.HashMap<String, Object>() {{}}); } catch(Exception _e) { throw new RuntimeException(_e); } });
            }
            ((java.util.List<Object>)((java.util.List<Object>)Helpers.GetValue(storedOrderBook, "cache"))).add(data);
            return;
        } else if (Helpers.isTrue(Helpers.isGreaterThanOrEqual(nonce, deltaEnd)))
        {
            return;
        }
        this.handleDelta(storedOrderBook, data);
        client.resolve(storedOrderBook, messageHash);
    }

    public Object getCacheIndex(Object orderbook, Object cache)
    {
        Object firstDelta = this.safeValue(cache, 0);
        Object nonce = this.safeInteger(orderbook, "nonce");
        Object firstDeltaStart = this.safeInteger(firstDelta, "sequence");
        if (Helpers.isTrue(Helpers.isLessThan(nonce, Helpers.subtract(firstDeltaStart, 1))))
        {
            return Helpers.opNeg(1);
        }
        for (var i = 0; Helpers.isLessThan(i, Helpers.getArrayLength(cache)); i++)
        {
            Object delta = Helpers.GetValue(cache, i);
            Object deltaStart = this.safeInteger(delta, "sequence");
            if (Helpers.isTrue(Helpers.isLessThan(nonce, Helpers.subtract(deltaStart, 1))))
            {
                return i;
            }
        }
        return Helpers.getArrayLength(cache);
    }

