    /**
     * @method
     * @name kucoinfutures#watchOrders
     * @description watches information on multiple orders made by the user
     * @see https://docs.kucoin.com/futures/#trade-orders-according-to-the-market
     * @param {string} symbol unified market symbol of the market orders were made in
     * @param {int} [since] the earliest time in ms to fetch orders for
     * @param {int} [limit] the maximum number of order structures to retrieve
     * @param {object} [params] extra parameters specific to the exchange API endpoint
     * @returns {object[]} a list of [order structures]{@link https://docs.ccxt.com/?id=order-structure}
     */
    public java.util.concurrent.CompletableFuture<Object> watchOrders(Object... optionalArgs)
    {

        return java.util.concurrent.CompletableFuture.supplyAsync(() -> {

            Object symbol = Helpers.getArg(optionalArgs, 0, null);
            Object since = Helpers.getArg(optionalArgs, 1, null);
            Object limit = Helpers.getArg(optionalArgs, 2, null);
            Object parameters = Helpers.getArg(optionalArgs, 3, new java.util.HashMap<String, Object>() {{}});
            (this.loadMarkets()).join();
            Object url = (this.negotiate(true)).join();
            Object topic = "/contractMarket/tradeOrders";
            Object request = new java.util.HashMap<String, Object>() {{
                put( "privateChannel", true );
            }};
            Object messageHash = "orders";
            if (Helpers.isTrue(!Helpers.isEqual(symbol, null)))
            {
                Object market = this.market(symbol);
                symbol = Helpers.GetValue(market, "symbol");
                messageHash = Helpers.add(Helpers.add(messageHash, ":"), symbol);
            }
            Object orders = (this.subscribe(url, messageHash, topic, null, this.extend(request, parameters))).join();
            if (Helpers.isTrue(this.newUpdates))
            {
                limit = Helpers.callDynamically(orders, "getLimit", new Object[]{symbol, limit});
            }
            return this.filterBySymbolSinceLimit(orders, symbol, since, limit, true);
        }, io.github.ccxt.Exchange.VIRTUAL_EXECUTOR);

    }

    public Object parseWsOrderStatus(Object status)
    {
        Object statuses = new java.util.HashMap<String, Object>() {{
            put( "open", "open" );
            put( "filled", "closed" );
            put( "match", "open" );
            put( "update", "open" );
            put( "canceled", "canceled" );
        }};
        return this.safeString(statuses, status, status);
    }

    public Object parseWsOrder(Object order, Object... optionalArgs)
    {
        //
        //         "symbol": "XCAD-USDT",
        //     {
        //         "orderType": "limit",
        //         "side": "buy",
        //         "orderId": "6249167327218b000135e749",
        //         "type": "canceled",
        //         "orderTime": 1648957043065280224,
        //         "size": "100.452",
        //         "filledSize": "0",
        //         "price": "2.9635",
        //         "clientOid": "buy-XCAD-USDT-1648957043010159",
        //         "remainSize": "0",
        //         "status": "done",
        //         "ts": 1648957054031001037
        //     }
        //
        Object market = Helpers.getArg(optionalArgs, 0, null);
        Object id = this.safeString(order, "orderId");
        Object clientOrderId = this.safeString(order, "clientOid");
        Object orderType = this.safeStringLower(order, "orderType");
        Object price = this.safeString(order, "price");
        Object filled = this.safeString(order, "filledSize");
        Object amount = this.safeString(order, "size");
        Object rawType = this.safeString(order, "type");
        Object status = this.parseWsOrderStatus(rawType);
        Object timestamp = this.safeIntegerProduct(order, "orderTime", 0.000001);
        Object marketId = this.safeString(order, "symbol");
        market = this.safeMarket(marketId, market);
        Object symbol = Helpers.GetValue(market, "symbol");
        Object side = this.safeStringLower(order, "side");
        return this.safeOrder(new java.util.HashMap<String, Object>() {{
            put( "info", order );
            put( "symbol", symbol );
            put( "id", id );
            put( "clientOrderId", clientOrderId );
            put( "timestamp", timestamp );
            put( "datetime", Kucoinfutures.this.iso8601(timestamp) );
            put( "lastTradeTimestamp", null );
            put( "type", orderType );
            put( "timeInForce", null );
            put( "postOnly", null );
            put( "side", side );
            put( "price", price );
            put( "stopPrice", null );
            put( "amount", amount );
            put( "cost", null );
            put( "average", null );
            put( "filled", filled );
            put( "remaining", null );
            put( "status", status );
            put( "fee", null );
            put( "trades", null );
        }}, market);
    }

    public void handleOrder(Client client, Object message)
    {
        Object messageHash = "orders";
        Object data = this.safeValue(message, "data");
        Object parsed = this.parseWsOrder(data);
        Object symbol = this.safeString(parsed, "symbol");
        Object orderId = this.safeString(parsed, "id");
        if (Helpers.isTrue(!Helpers.isEqual(symbol, null)))
        {
            if (Helpers.isTrue(Helpers.isEqual(this.orders, null)))
            {
                Object limit = this.safeInteger(this.options, "ordersLimit", 1000);
                this.orders = new ArrayCache.ArrayCacheBySymbolById(((Number)limit).intValue());
            }
            Object cachedOrders = this.orders;
            Object orders = this.safeValue(((io.github.ccxt.ws.ArrayCache)cachedOrders).hashmap, symbol, new java.util.HashMap<String, Object>() {{}});
            Object order = this.safeValue(orders, orderId);
            if (Helpers.isTrue(!Helpers.isEqual(order, null)))
            {
                // todo add others to calculate average etc
                Object stopPrice = this.safeValue(order, "stopPrice");
                if (Helpers.isTrue(!Helpers.isEqual(stopPrice, null)))
                {
                    Helpers.addElementToObject(parsed, "stopPrice", stopPrice);
                }
                if (Helpers.isTrue(Helpers.isEqual(Helpers.GetValue(order, "status"), "closed")))
                {
                    Helpers.addElementToObject(parsed, "status", "closed");
                }
            }
            Helpers.callDynamically(cachedOrders, "append", new Object[]{parsed});
            client.resolve(this.orders, messageHash);
            Object symbolSpecificMessageHash = Helpers.add(Helpers.add(messageHash, ":"), symbol);
            client.resolve(this.orders, symbolSpecificMessageHash);
        }
    }

