    public java.util.concurrent.CompletableFuture<Object> fetchBalanceSnapshot(Client client, Object message)
    {

        return java.util.concurrent.CompletableFuture.supplyAsync(() -> {

            (this.loadMarkets()).join();
            this.checkRequiredCredentials();
            Object messageHash = "balance";
            Object selectedType = this.safeString2(this.options, "watchBalance", "defaultType", "swap"); // spot, margin, main, funding, future, mining, trade, contract, pool
            Object parameters = new java.util.HashMap<String, Object>() {{
                put( "type", selectedType );
            }};
            Object snapshot = (this.fetchBalance(parameters)).join();
            //
            //    {
            //        "info": {
            //            "code": "200000",
            //            "data": {
            //                "accountEquity": 0.0350281903,
            //                "unrealisedPNL": 0,
            //                "marginBalance": 0.0350281903,
            //                "positionMargin": 0,
            //                "orderMargin": 0,
            //                "frozenFunds": 0,
            //                "availableBalance": 0.0350281903,
            //                "currency": "USDT"
            //            }
            //        },
            //        "timestamp": undefined,
            //        "datetime": undefined,
            //        "USDT": {
            //            "free": 0.0350281903,
            //            "used": 0,
            //            "total": 0.0350281903
            //        },
            //        "free": {
            //            "USDT": 0.0350281903
            //        },
            //        "used": {
            //            "USDT": 0
            //        },
            //        "total": {
            //            "USDT": 0.0350281903
            //        }
            //    }
            //
            Object keys = new java.util.ArrayList<Object>(((java.util.Map<String, Object>)snapshot).keySet());
            for (var i = 0; Helpers.isLessThan(i, Helpers.getArrayLength(keys)); i++)
            {
                Object code = Helpers.GetValue(keys, i);
                if (Helpers.isTrue(Helpers.isTrue(Helpers.isTrue(Helpers.isTrue(Helpers.isTrue(Helpers.isTrue(!Helpers.isEqual(code, "free")) && Helpers.isTrue(!Helpers.isEqual(code, "used"))) && Helpers.isTrue(!Helpers.isEqual(code, "total"))) && Helpers.isTrue(!Helpers.isEqual(code, "timestamp"))) && Helpers.isTrue(!Helpers.isEqual(code, "datetime"))) && Helpers.isTrue(!Helpers.isEqual(code, "info"))))
                {
                    Helpers.addElementToObject(this.balance, code, Helpers.GetValue(snapshot, code));
                }
            }
            
            Helpers.addElementToObject(this.balance, "info", this.safeValue(snapshot, "info", new java.util.HashMap<String, Object>() {{}}));
            client.resolve(this.balance, messageHash);
            return null;
        }, io.github.ccxt.Exchange.VIRTUAL_EXECUTOR);

    }

