    public Object ping(Client client)
    {
        // kucoin does not support built-in ws protocol-level ping-pong
        // instead it requires a custom json-based text ping-pong
        // https://docs.kucoin.com/#ping
        Object id = String.valueOf(this.requestId());
        return new java.util.HashMap<String, Object>() {{
            put( "id", id );
            put( "type", "ping" );
        }};
    }

    public Object handlePong(Client client, Object message)
    {
        // https://docs.kucoin.com/#ping
        client.lastPong = ((Number)this.milliseconds()).longValue();
        return message;
    }

    public Object handleErrorMessage(Client client, Object message)
    {
        //
        //    {
        //        "id": "64d8732c856851144bded10d",
        //        "type": "error",
        //        "code": 401,
        //        "data": "token is expired"
        //    }
        //
        Object data = this.safeString(message, "data", "");
        if (Helpers.isTrue(Helpers.isEqual(data, "token is expired")))
        {
            Object type = "public";
            if (Helpers.isTrue(Helpers.isGreaterThanOrEqual(Helpers.getIndexOf(client.url, "connectId=private"), 0)))
            {
                type = "private";
            }
            Helpers.addElementToObject(Helpers.GetValue(this.options, "urls"), type, null);
        }
        this.handleErrors(1, "", client.url, "", new java.util.HashMap<String, Object>() {{}}, data, message, new java.util.HashMap<String, Object>() {{}}, new java.util.HashMap<String, Object>() {{}});
        return true;
    }

    public void handleSubscriptionStatus(Client client, Object message)
    {
        //
        //     {
        //         "id": "1578090438322",
        //         "type": "ack"
        //     }
        //
        Object id = this.safeString(message, "id");
        if (!Helpers.isTrue((Helpers.inOp(client.subscriptions, id))))
        {
            return;
        }
        Object subscriptionHash = this.safeString(client.subscriptions, id);
        Object subscription = this.safeValue(client.subscriptions, subscriptionHash);
        ((java.util.Map<String,Object>)client.subscriptions).remove((String)id);
        Object method = this.safeValue(subscription, "method");
        if (Helpers.isTrue(!Helpers.isEqual(method, null)))
        {
            Helpers.callDynamically(this, method, new Object[] {client, message, subscription});
        }
        Object isUnSub = this.safeBool(subscription, "unsubscribe", false);
        if (Helpers.isTrue(isUnSub))
        {
            Object messageHashes = this.safeList(subscription, "messageHashes", new java.util.ArrayList<Object>(java.util.Arrays.asList()));
            Object subMessageHashes = this.safeList(subscription, "subMessageHashes", new java.util.ArrayList<Object>(java.util.Arrays.asList()));
            for (var i = 0; Helpers.isLessThan(i, Helpers.getArrayLength(messageHashes)); i++)
            {
                Object messageHash = Helpers.GetValue(messageHashes, i);
                Object subHash = Helpers.GetValue(subMessageHashes, i);
                this.cleanUnsubscription(client, subHash, messageHash);
            }
            this.cleanCache(subscription);
        }
    }

    public void handleMessage(Client client, Object message)
    {
        Object type = this.safeString(message, "type");
        Object methods = new java.util.HashMap<String, Object>() {{
            put( "welcome", "handleSystemStatus");
            put( "message", "handleSubject");
            put( "pong", "handlePong");
            put( "error", "handleErrorMessage");
            put( "ack", "handleSubscriptionStatus");
        }};
        Object method = this.safeValue(methods, type);
        if (Helpers.isTrue(!Helpers.isEqual(method, null)))
        {
            Helpers.callDynamically(this, method, new Object[] {client, message});
        }
    }
